def export_products_to_json(html):
    soup = BeautifulSoup(html, 'html.parser')
    products = []
    
    # Define our static category
    category_val = 'cosmetics'
    
    # Find all product containers
    tile_containers = soup.find_all('div', {'data-comp': lambda x: x and 'ProductTile' in x})
    
    for tile in tile_containers:
        link_tag = tile.find('a', class_='css-11s14hs')
        if not link_tag:
            continue
            
        # --- Extraction Logic ---
        
        # SKU: Extracted from the data attribute or the URL query string
        sku = link_tag.get('data-cnstrc-item-variation-id')
        
        brand = tile.find('span', class_='css-qs99nc').get_text(strip=True) if tile.find('span', class_='css-qs99nc') else None
        product_name = tile.find('span', class_='css-10qekqh').get_text(strip=True) if tile.find('span', class_='css-10qekqh') else None
        
        # Star Rating
        star_tag = tile.find('span', {'data-comp': 'StarRating '})
        star_review = star_tag['aria-label'].split(' ')[0] if star_tag and star_tag.has_attr('aria-label') else None

        # Number of Reviews
        num_reviews = tile.find('span', {'data-at': 'review_count'}).get_text(strip=True) if tile.find('span', {'data-at': 'review_count'}) else None

        # Pricing logic
        price_container = tile.find('b', class_='css-o1eshd')
        price, sale_price, value_price = None, None, None

        if price_container:
            val_tag = price_container.find('span', class_='css-16twmm3')
            if val_tag:
                value_price = val_tag.get_text(strip=True).strip('()').replace(' value', '')
            
            sale_price_tag = price_container.find('p', class_='css-10aswgz')
            if sale_price_tag:
                sale_price = sale_price_tag.get_text(strip=True)
                reg_price_tag = price_container.find('span', class_='css-l4jk8r')
                price = reg_price_tag.get_text(strip=True) if reg_price_tag else sale_price
            else:
                main_price_tag = price_container.find('span', class_='css-0')
                price = main_price_tag.get_text(strip=True) if main_price_tag else price_container.get_text(strip=True).split('(')[0].strip()

        img_tag = tile.find('img', class_='css-tl1r8e')
        image_url = img_tag['src'] if img_tag else None

        # Append data to list
        products.append({
            "sku": sku,
            "brand": brand,
            "title": product_name,
            "category": category_val,
            "star_review": star_review,
            "number_of_reviews": num_reviews,
            "price": price,
            "value": value_price,
            "sale_price": sale_price,
            "link": "https://www.sephora.com" + link_tag['href'] if link_tag.has_attr('href') else None,
            "image_link": image_url
        })

    # --- CSV Export Logic ---
    """# Generate filename using current timestamp (e.g., 2024-05-20_14-30-05.csv)
    timestamp = datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
    filename = f"products_{timestamp}.csv"
    
    if products:
        keys = products[0].keys()
        with open(filename, 'w', newline='', encoding='utf-8') as output_file:
            dict_writer = csv.DictWriter(output_file, fieldnames=keys)
            dict_writer.writeheader()
            dict_writer.writerows(products)
        print(f"Successfully exported {len(products)} items to {filename}")
    else:
        print("No products found to export.")"""

    # --- JSON Export Logic ---
    
    # Generate filename using current timestamp
    timestamp = datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
    filename = f"products_{timestamp}.json"
    
    if products:
        with open(filename, 'w', encoding='utf-8') as output_file:
            # indent=4 makes the JSON file human-readable
            # ensure_ascii=False handles special characters correctly
            json.dump(products, output_file, indent=4, ensure_ascii=False)
        print(f"Successfully exported {len(products)} items to {filename}")
    else:
        print("No products found to export.")

# Run the script
if __name__ == "__main__":
    export_products_to_json(html_content)
